sys_script_client.script:
function onSubmit() {
	var digicertOneAPIKey = "digicert_one_api_key";
    var property = g_form.getValue("property");
    if (property === digicertOneAPIKey) {
        var token = g_form.getValue("value");
        var ga = new GlideAjax("APITokenAjaxProcessor");
        ga.addParam('sysparm_name', 'validate');
        ga.addParam("token", token);
        ga.getXMLAnswer(function(response) {
            var result = JSON.parse(response);
            if (result) {
                g_form.addInfoMessage(getMessage("API Key has been added successfully!"));
				g_form.modified = false;
            } else {
                g_form.addErrorMessage(getMessage("API Key is not valid!"));
            }
        });
    }

    return false;
}
